import json, csv, pandas as pd

def norm_date(v):
    if v is None: return None
    if isinstance(v, str): return v[:10]
    try: return pd.to_datetime(v).strftime('%Y-%m-%d')
    except Exception: return str(v)[:10]

# maps to unified field
FMAP = {
    'user_id':'user_id','id':'user_id','userId':'user_id',
    'email':'email','email_address':'email',
    'full_name':'name','name':'name','userName':'name',
    'registration_date':'created_date','created_at':'created_date','joined':'created_date',
    'status':'status',
}

def unify(rec):
    out={}
    for k,v in rec.items():
        if k in FMAP:
            u=FMAP[k]
            if u=='created_date': v=norm_date(v)
            if u=='user_id': v=int(v)
            out[u]=v
    return out

a=[unify(r) for r in json.load(open('/data/source_a/users.json'))]
b=[unify(r) for r in csv.DictReader(open('/data/source_b/users.csv'))]
c=[unify(r) for r in pd.read_parquet('/data/source_c/users.parquet').to_dict('records')]

sources=[('source_a',a),('source_b',b),('source_c',c)]  # priority order

# index by user_id per source
by_src={name:{r['user_id']:r for r in rows} for name,rows in sources}
all_ids=sorted({uid for m in by_src.values() for uid in m})

FIELDS=['name','email','created_date','status']
merged=[]
conflicts=[]
for uid in all_ids:
    row={'user_id':uid}
    for f in FIELDS:
        vals={}  # source->value (only sources that have this user AND field non-null)
        for sname,_ in sources:
            r=by_src[sname].get(uid)
            if r is not None and f in r and r[f] is not None:
                vals[sname]=r[f]
        if not vals: 
            row[f]=None
            continue
        # selected = highest priority present
        selected=None
        for sname,_ in sources:
            if sname in vals:
                selected=vals[sname]; break
        row[f]=selected
        # conflict if >1 distinct value among sources having this user+field
        if len(set(vals.values()))>1:
            conflicts.append({'user_id':uid,'field':f,
                'values':{s:vals[s] for s in ('source_a','source_b','source_c') if s in vals},
                'selected':selected})
    merged.append(row)

df=pd.DataFrame(merged, columns=['user_id','name','email','created_date','status'])
df['user_id']=df['user_id'].astype('int64')
for col in ['name','email','created_date','status']:
    df[col]=df[col].astype('object')
df.to_parquet('/app/merged_users.parquet', index=False)

json.dump({'total_conflicts':len(conflicts),'conflicts':conflicts},
          open('/app/conflicts.json','w'), indent=2)
print(df.to_string())
print('conflicts',len(conflicts))
PY
